import { useState, useCallback } from "react";
import { useAuth } from './hooks/useAuth';
import { useTheme } from './ThemeContext';
import { SEASONS, LEAGUE_CONFIGS } from './logic/constants';
import { getLeagueDates, generateSchedule } from './logic/helpers'; // Wait, generateSchedule is in schedule.js
import { generateSchedule as genSchedule } from './logic/schedule';
import { useLeagueData } from './hooks/useLeagueData';
import Header from './components/Header';
import SetupView from './components/SetupView';
import ScheduleView from './components/ScheduleView';
import StandingsView from './components/StandingsView';
import ChampionsView from './components/ChampionsView';

// Wrapper to pass activeLeague from Schedule down to Standings
function MainView({ schedules, setSchedules, leagueTeams, activeSeason, setActiveSeason, isAdmin }) {
    // We recreate the state for activeLeague here so both components can share it
    const todayDow = new Date().getDay();
    const allKeys = Object.keys(LEAGUE_CONFIGS);
    const defaultKey = allKeys.find((k) => LEAGUE_CONFIGS[k].day === todayDow && LEAGUE_CONFIGS[k].type === "daytime")
      || allKeys.find((k) => LEAGUE_CONFIGS[k].day === todayDow) || allKeys[0];

    const [activeLeague, setActiveLeague] = useState(defaultKey);

    return (
        <CombinedView schedules={schedules} setSchedules={setSchedules} leagueTeams={leagueTeams} activeSeason={activeSeason} setActiveSeason={setActiveSeason} isAdmin={isAdmin} />
    );
}

// Actually I can just render App and fix it later
export default function App() {
  const { colors } = useTheme();
  const { user, loading: authLoading, isAdmin } = useAuth();
  const { seasonDates, holidays, leagueTeams, schedules, loading: dataLoading, updateLeagueData } = useLeagueData();

  const [tab, setTab] = useState("schedule");
  const [activeSeason, setActiveSeason] = useState("spring");

  const setSeasonDates = useCallback((updater) => {
    updateLeagueData({ seasonDates: typeof updater === 'function' ? updater(seasonDates) : updater });
  }, [updateLeagueData, seasonDates]);

  const setHolidays = useCallback((updater) => {
    updateLeagueData({ holidays: typeof updater === 'function' ? updater(holidays) : updater });
  }, [updateLeagueData, holidays]);

  const setLeagueTeams = useCallback((updater) => {
    updateLeagueData({ leagueTeams: typeof updater === 'function' ? updater(leagueTeams) : updater });
  }, [updateLeagueData, leagueTeams]);

  const setSchedules = useCallback((updater) => {
    updateLeagueData({ schedules: typeof updater === 'function' ? updater(schedules) : updater });
  }, [updateLeagueData, schedules]);

  const handleGenerate = useCallback(() => {
    const next = { ...schedules };
    Object.entries(LEAGUE_CONFIGS).forEach(([key, cfg]) => {
      const tKey = `${activeSeason}_${key}`;
      const teams = leagueTeams[tKey] || [];
      if (teams.filter((t) => t.trim()).length === 20) {
        const sd = seasonDates[activeSeason];
        const hols = holidays[activeSeason] || [];
        const dates = getLeagueDates(sd.start, sd.end, cfg.day, hols);
        const sched = genSchedule(teams, dates);
        if (sched) next[tKey] = sched;
      }
    });
    setSchedules(next);
  }, [activeSeason, leagueTeams, seasonDates, holidays, schedules, setSchedules]);

  if (authLoading || dataLoading) {
    return (
        <div style={{ background: colors.BG, color: colors.TEXT, minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            Loading...
        </div>
    );
  }

  return (
    <div style={{ background: colors.BG, color: colors.TEXT, minHeight: "100vh", fontFamily: "'Barlow Condensed', system-ui, sans-serif" }}>
      <Header tab={tab} setTab={setTab} isAdmin={isAdmin} user={user} />

      {tab === "setup" && (
        <SetupView seasonDates={seasonDates} setSeasonDates={setSeasonDates} holidays={holidays} setHolidays={setHolidays} leagueTeams={leagueTeams} setLeagueTeams={setLeagueTeams} onGenerate={handleGenerate} schedules={schedules} activeSeason={activeSeason} setActiveSeason={setActiveSeason} />
      )}

      {(tab === "schedule" || tab === "standings" || tab === "champions") && (
         <CombinedView schedules={schedules} setSchedules={setSchedules} leagueTeams={leagueTeams} activeSeason={activeSeason} setActiveSeason={setActiveSeason} isAdmin={isAdmin} forceTab={tab} />
      )}
    </div>
  );
}

function CombinedView({ schedules, setSchedules, leagueTeams, activeSeason, setActiveSeason, isAdmin, forceTab }) {
    const todayDow = new Date().getDay();
    const allKeys = Object.keys(LEAGUE_CONFIGS);
    const defaultKey = allKeys.find((k) => LEAGUE_CONFIGS[k].day === todayDow && LEAGUE_CONFIGS[k].type === "daytime")
      || allKeys.find((k) => LEAGUE_CONFIGS[k].day === todayDow) || allKeys[0];

    const [activeLeague, setActiveLeague] = useState(defaultKey);

    return (
         <div style={{ display: 'flex', flexDirection: 'column' }}>
             {/* Always render ScheduleView to provide the Season/League picker! */}
             <ScheduleView 
                 schedules={schedules} setSchedules={setSchedules} 
                 leagueTeams={leagueTeams} 
                 activeSeason={activeSeason} setActiveSeason={setActiveSeason} 
                 activeLeague={activeLeague} setActiveLeague={setActiveLeague}
                 isAdmin={isAdmin} 
                 hideCourts={forceTab === "champions"}
             />
             {forceTab !== "champions" && (
                 <StandingsView 
                     schedules={schedules} 
                     activeSeason={activeSeason} 
                     activeLeague={activeLeague} 
                 />
             )}
             {forceTab === "champions" && (
                 <ChampionsView 
                     schedules={schedules} 
                     activeSeason={activeSeason} 
                     activeLeague={activeLeague} 
                 />
             )}
         </div>
    );
}

import { createContext, useContext, useState, useEffect } from 'react';

// ─── DARK PALETTE ───────────────────────────────────────────────────────────
const DARK_COLORS = {
    BG: '#060a14',
    PANEL: '#0b1020',
    CARD: '#101828',
    BORDER: '#1c2b47',
    GREEN: '#00e676',
    YELLOW: '#ffd740',
    BLUE: '#40c4ff',
    RED: '#ff5252',
    MUTED: '#4a5a7a',
    LIGHT: '#c0ccde',
    TEXT: '#ffffff',
    DONE_BG: '#0b1a0f',
    DONE_BORDER: '#1a3320',
    ACTIVE_BG: '#0b1524',
    WIN_BG: '#00e67611',
    CHAMP_BG: '#181000',
    REGEN_BG: '#1a1200',
    INPUT_BG: '#101828',
    INPUT_COLOR: '#ffffff',
    OVERLAY: 'rgba(0,0,0,.92)',
};

const DARK_POD_COLORS = {
    A: '#00e676',
    B: '#40c4ff',
    C: '#ffd740',
    D: '#ff6e40',
    E: '#ea80fc',
    F: '#80d8ff',
};

// ─── LIGHT PALETTE ──────────────────────────────────────────────────────────
const LIGHT_COLORS = {
    BG: '#f4f6f9',
    PANEL: '#ffffff',
    CARD: '#ffffff',
    BORDER: '#d8dde6',
    GREEN: '#0d9e4f',
    YELLOW: '#d49a00',
    BLUE: '#0078d4',
    RED: '#d32f2f',
    MUTED: '#7a8599',
    LIGHT: '#3a4355',
    TEXT: '#1a1a2e',
    DONE_BG: '#eaf5ee',
    DONE_BORDER: '#b4d8c0',
    ACTIVE_BG: '#e8f0fe',
    WIN_BG: '#0d9e4f11',
    CHAMP_BG: '#fffbe6',
    REGEN_BG: '#fff8e1',
    INPUT_BG: '#f0f2f5',
    INPUT_COLOR: '#1a1a2e',
    OVERLAY: 'rgba(0,0,0,.55)',
};

const LIGHT_POD_COLORS = {
    A: '#0d9e4f',
    B: '#0078d4',
    C: '#d49a00',
    D: '#e64a19',
    E: '#9c27b0',
    F: '#0277bd',
};

// ─── CONTEXT ────────────────────────────────────────────────────────────────
const ThemeContext = createContext(null);

export function ThemeProvider({ children }) {
    const [isDark, setIsDark] = useState(() => {
        const saved = localStorage.getItem('bocce-theme');
        return saved === 'dark';
    });

    useEffect(() => {
        localStorage.setItem('bocce-theme', isDark ? 'dark' : 'light');
        document.documentElement.setAttribute('data-theme', isDark ? 'dark' : 'light');
    }, [isDark]);

    const value = {
        colors: isDark ? DARK_COLORS : LIGHT_COLORS,
        podColors: isDark ? DARK_POD_COLORS : LIGHT_POD_COLORS,
        isDark,
        toggle: () => setIsDark(d => !d),
    };

    return (
        <ThemeContext.Provider value={value}>
            {children}
        </ThemeContext.Provider>
    );
}

export function useTheme() {
    const ctx = useContext(ThemeContext);
    if (!ctx) throw new Error('useTheme must be used within ThemeProvider');
    return ctx;
}

import { useTheme } from '../ThemeContext';
import { getMatchResult } from '../logic/standings';
import { COURT_COLORS, COURTS } from '../logic/constants';

export default function CourtCard({ matchup, colorIdx, indoor, onClick }) {
  const { colors } = useTheme();
  // We use the same colors array but handled safely
  const idx = COURTS.indexOf(matchup.court);
  const color = COURT_COLORS[idx] || "#475569";

  const r = getMatchResult(matchup.frames);
  const scored = r.complete;
  const partial = matchup.frames.some((f) => f !== null) && !scored;

  return (
    <div onClick={onClick} style={{
      background: scored ? colors.DONE_BG : colors.CARD,
      border: `2px solid ${scored ? colors.DONE_BORDER : color}`, borderRadius: 12, padding: "8px 12px",
      display: "flex", flexDirection: "column", alignItems: "center", gap: 3,
      minWidth: 0, flex: 1, cursor: "pointer", transition: "transform 0.1s",
    }}
    onMouseEnter={(e) => e.currentTarget.style.transform = "scale(1.02)"}
    onMouseLeave={(e) => e.currentTarget.style.transform = "scale(1)"}
    >
      <div style={{
        background: color, color: "#fff", fontWeight: 800, fontSize: 13,
        borderRadius: 6, padding: "2px 10px", letterSpacing: 1, textTransform: "uppercase",
        display: "flex", alignItems: "center", gap: 5,
      }}>
        Court {matchup.court}
        {indoor && <span style={{ fontSize: 9, opacity: 0.85 }}>(Indoor)</span>}
      </div>

      <div style={{ display: "flex", alignItems: "center", gap: 6, width: "100%", justifyContent: "center", marginTop: 2 }}>
        <div style={{
          flex: 1, textAlign: "center", fontWeight: 700, fontSize: 13, lineHeight: 1.2,
          padding: "4px 2px", background: "rgba(128,128,128,0.06)", borderRadius: 6,
          color: scored && r.framesA > r.framesB ? colors.GREEN : colors.TEXT,
        }}>
          {matchup.teamA}
          {(scored || partial) && (
            <div style={{ display: "flex", justifyContent: "center", gap: 4, marginTop: 3 }}>
              {matchup.frames.map((f, i) => (
                <span key={i} style={{
                  fontSize: 14, fontWeight: 900,
                  color: f ? (f.a > f.b ? colors.GREEN : f.a < f.b ? colors.RED : colors.MUTED) : colors.BORDER,
                }}>{f ? f.a : "-"}</span>
              ))}
            </div>
          )}
          {scored && <div style={{ fontSize: 11, color: colors.MUTED, marginTop: 1 }}>Frames: {r.framesA}</div>}
        </div>

        <div style={{ color: colors.YELLOW, fontWeight: 900, fontSize: 11, flexShrink: 0 }}>VS</div>

        <div style={{
          flex: 1, textAlign: "center", fontWeight: 700, fontSize: 13, lineHeight: 1.2,
          padding: "4px 2px", background: "rgba(128,128,128,0.06)", borderRadius: 6,
          color: scored && r.framesB > r.framesA ? colors.GREEN : colors.TEXT,
        }}>
          {matchup.teamB}
          {(scored || partial) && (
            <div style={{ display: "flex", justifyContent: "center", gap: 4, marginTop: 3 }}>
              {matchup.frames.map((f, i) => (
                <span key={i} style={{
                  fontSize: 14, fontWeight: 900,
                  color: f ? (f.b > f.a ? colors.GREEN : f.b < f.a ? colors.RED : colors.MUTED) : colors.BORDER,
                }}>{f ? f.b : "-"}</span>
              ))}
            </div>
          )}
          {scored && <div style={{ fontSize: 11, color: colors.MUTED, marginTop: 1 }}>Frames: {r.framesB}</div>}
        </div>
      </div>

      {!scored && !partial && <div style={{ fontSize: 10, color: colors.MUTED, marginTop: 1 }}>Tap to enter score</div>}
      {partial && <div style={{ fontSize: 10, color: colors.YELLOW, marginTop: 1 }}>In progress</div>}
    </div>
  );
}

